17	
18	`include "defines.svh"
19	
20	import defines::*;
21	
22	//
23	// Storage for control registers.
24	// Also contains interrupt handling logic.
25	//
26	
27	module control_registers
28	    #(parameter CORE_ID = 0,
29	    parameter NUM_INTERRUPTS = 16,
30	    parameter NUM_PERF_EVENTS = 8,
31	    parameter EVENT_IDX_WIDTH = $clog2(NUM_PERF_EVENTS))
32	    (input                                  clk,
33	    input                                   reset,
34	
35	    input [NUM_INTERRUPTS - 1:0]            interrupt_req,
36	
37	    // To multiple stages
38	    output scalar_t                         cr_eret_address[`THREADS_PER_CORE],
39	    output logic                            cr_mmu_en[`THREADS_PER_CORE],
40	    output logic                            cr_supervisor_en[`THREADS_PER_CORE],
41	    output logic[ASID_WIDTH - 1:0]          cr_current_asid[`THREADS_PER_CORE],
42	
43	    // To nyuzi
44	    output logic[TOTAL_THREADS - 1:0]       cr_suspend_thread,
45	    output logic[TOTAL_THREADS - 1:0]       cr_resume_thread,
46	
47	    // To instruction_decode_stage
48	    output logic[`THREADS_PER_CORE - 1:0]   cr_interrupt_pending,
49	    output local_thread_bitmap_t            cr_interrupt_en,
50	
51	    // From dcache_data_stage
52	    // dd_xxx signals are unregistered. dt_thread_idx represents thread going into
53	    // dcache_data_stage)
54	    input local_thread_idx_t                dt_thread_idx,
55	    input                                   dd_creg_write_en,
56	    input                                   dd_creg_read_en,
57	    input control_register_t                dd_creg_index,
58	    input scalar_t                          dd_creg_write_val,
59	
60	    // From writeback_stage
61	    input                                   wb_trap,
62	    input                                   wb_eret,
63	    input trap_cause_t                      wb_trap_cause,
64	    input scalar_t                          wb_trap_pc,
65	    input scalar_t                          wb_trap_access_vaddr,
66	    input local_thread_idx_t                wb_rollback_thread_idx,
67	    input subcycle_t                        wb_trap_subcycle,
68	    input syscall_index_t                   wb_syscall_index,
69	
70	    // To writeback_stage
71	    output scalar_t                         cr_creg_read_val,
72	    output subcycle_t                       cr_eret_subcycle[`THREADS_PER_CORE],
73	    output scalar_t                         cr_trap_handler,
74	    output scalar_t                         cr_tlb_miss_handler,
75	
76	    // To/from performance_counters
77	    output logic[EVENT_IDX_WIDTH - 1:0]     cr_perf_event_select0,
78	    output logic[EVENT_IDX_WIDTH - 1:0]     cr_perf_event_select1,
79	    input[63:0]                             perf_event_count0,
80	    input[63:0]                             perf_event_count1,
81	
82	    // To/from on_chip_debugger
83	    input scalar_t                          ocd_data_from_host,
84	    input                                   ocd_data_update,
85	    output scalar_t                         cr_data_to_host);
86	
87	    // One is for current state. Maximum nested traps is TRAP_LEVELS - 1.
88	    localparam TRAP_LEVELS = 3;
89	
90	    typedef struct packed {
91	        logic supervisor_en;
92	        logic mmu_en;
93	        logic interrupt_en;
94	    } flags_t;
95	
96	    typedef struct packed {
97	        flags_t flags;
98	        scalar_t scratchpad0;
99	        scalar_t scratchpad1;
100	
101	        // Information about last trap
102	        trap_cause_t trap_cause;
103	        scalar_t trap_pc;
104	        scalar_t trap_access_addr;
105	        subcycle_t trap_subcycle;
106	        syscall_index_t syscall_index;
107	    } trap_state_t;
108	
109	    trap_state_t trap_state[`THREADS_PER_CORE][TRAP_LEVELS];
110	    scalar_t page_dir_base[`THREADS_PER_CORE];
111	    scalar_t cycle_count;
112	    logic[NUM_INTERRUPTS - 1:0] interrupt_mask[`THREADS_PER_CORE];
113	    logic[NUM_INTERRUPTS - 1:0] interrupt_pending[`THREADS_PER_CORE];
114	    logic[NUM_INTERRUPTS - 1:0] interrupt_edge_latched[`THREADS_PER_CORE];
115	    logic[NUM_INTERRUPTS - 1:0] int_trigger_type;
116	    logic[NUM_INTERRUPTS - 1:0] interrupt_req_prev;
117	    logic[NUM_INTERRUPTS - 1:0] interrupt_edge;
118	    scalar_t jtag_data;
119	
120	    assign cr_data_to_host = jtag_data;
121	
122	    always_ff @(posedge clk, posedge reset)
123	    begin
124	        if (reset)
125	        begin
126	            for (int thread_idx = 0; thread_idx < `THREADS_PER_CORE; thread_idx++)
127	            begin
128	                trap_state[thread_idx][0] <= '0;
129	                trap_state[thread_idx][0].flags.supervisor_en <= 1'b1;
130	                cr_current_asid[thread_idx] <= '0;
131	                page_dir_base[thread_idx] <= '0;
132	                interrupt_mask[thread_idx] <= '0;
133	            end
134	
135	            // AUTORESET gets confused by all of the structure accesses
136	            // below, so the resets are all manual here. Be sure to add all registers
137	            // accessed below here.
138	            jtag_data <= '0;
139	            cr_tlb_miss_handler <= '0;
140	            cr_trap_handler <= '0;
141	            cycle_count <= '0;
142	            int_trigger_type <= '0;
143	            cr_suspend_thread <= '0;
144	            cr_resume_thread <= '0;
145	            cr_perf_event_select0 <= '0;
146	            cr_perf_event_select1 <= '0;
147	        end
148	        else
149	        begin
150	            // Ensure a read and write don't occur in the same cycle
151	            assert(!(dd_creg_write_en && dd_creg_read_en));
152	
153	            // A fault and eret are triggered from the same stage, so they
154	            // must not occur simultaneously (an eret can raise a fault if it
155	            // is not in supervisor mode, but wb_eret should not be asserted
156	            // in that case)
157	            assert(!(wb_trap && wb_eret));
158	
159	            cycle_count <= cycle_count + 1;
160	
161	            if (wb_trap)
162	            begin
163	                // Copy trap state
164	                for (int level = 0; level < TRAP_LEVELS - 1; level++)
165	                    trap_state[wb_rollback_thread_idx][level + 1] <= trap_state[wb_rollback_thread_idx][level];
166	
167	                // Dispatch fault
168	                trap_state[wb_rollback_thread_idx][0].trap_cause <= wb_trap_cause;
169	                trap_state[wb_rollback_thread_idx][0].trap_pc <= wb_trap_pc;
170	                trap_state[wb_rollback_thread_idx][0].trap_access_addr <= wb_trap_access_vaddr;
171	                trap_state[wb_rollback_thread_idx][0].syscall_index <= wb_syscall_index;
172	                trap_state[wb_rollback_thread_idx][0].trap_subcycle <= wb_trap_subcycle;
173	                trap_state[wb_rollback_thread_idx][0].flags.interrupt_en <= 0;    // Disable interrupts for this thread
174	                trap_state[wb_rollback_thread_idx][0].flags.supervisor_en <= 1;
175	                if (wb_trap_cause.trap_type == TT_TLB_MISS)
176	                    trap_state[wb_rollback_thread_idx][0].flags.mmu_en <= 0;
177	            end
178	
179	            if (wb_eret)
180	            begin
181	                // Restore nested interrupt state
182	                for (int level = 0; level < TRAP_LEVELS - 1; level++)
183	                    trap_state[wb_rollback_thread_idx][level] <= trap_state[wb_rollback_thread_idx][level + 1];
184	            end
185	
186	            //
187	            // Write logic
188	            //
189	            cr_suspend_thread <= '0;
190	            cr_resume_thread <= '0;
191	
192	            if (dd_creg_write_en)
193	            begin
194	                unique case (dd_creg_index)
195	                    CR_FLAGS:             trap_state[dt_thread_idx][0].flags <= flags_t'(dd_creg_write_val);
196	                    CR_SAVED_FLAGS:       trap_state[dt_thread_idx][1].flags <= flags_t'(dd_creg_write_val);
197	                    CR_TRAP_PC:           trap_state[dt_thread_idx][0].trap_pc <= dd_creg_write_val;
198	                    CR_TRAP_HANDLER:      cr_trap_handler <= dd_creg_write_val;
199	                    CR_TLB_MISS_HANDLER:  cr_tlb_miss_handler <= dd_creg_write_val;
200	                    CR_SCRATCHPAD0:       trap_state[dt_thread_idx][0].scratchpad0 <= dd_creg_write_val;
201	                    CR_SCRATCHPAD1:       trap_state[dt_thread_idx][0].scratchpad1 <= dd_creg_write_val;
202	                    CR_SUBCYCLE:          trap_state[dt_thread_idx][0].trap_subcycle <= subcycle_t'(dd_creg_write_val);
203	                    CR_CURRENT_ASID:      cr_current_asid[dt_thread_idx] <= dd_creg_write_val[ASID_WIDTH - 1:0];
204	                    CR_PAGE_DIR:          page_dir_base[dt_thread_idx] <= dd_creg_write_val;
205	                    CR_INTERRUPT_ENABLE:  interrupt_mask[dt_thread_idx] <= dd_creg_write_val[NUM_INTERRUPTS - 1:0];
206	                    CR_INTERRUPT_TRIGGER: int_trigger_type <= dd_creg_write_val[NUM_INTERRUPTS - 1:0];
207	                    CR_JTAG_DATA:         jtag_data <= dd_creg_write_val;
208	                    CR_SUSPEND_THREAD:    cr_suspend_thread <= dd_creg_write_val[TOTAL_THREADS - 1:0];
209	                    CR_RESUME_THREAD:     cr_resume_thread <= dd_creg_write_val[TOTAL_THREADS - 1:0];
210	                    CR_PERF_EVENT_SELECT0: cr_perf_event_select0 <= dd_creg_write_val[EVENT_IDX_WIDTH - 1:0];
211	                    CR_PERF_EVENT_SELECT1: cr_perf_event_select1 <= dd_creg_write_val[EVENT_IDX_WIDTH - 1:0];
212	                    default:
213	                        ;
214	                endcase
215	            end
216	            else if (ocd_data_update)
217	                jtag_data <= ocd_data_from_host;
218	        end
219	    end
220	
221	    always @(posedge clk, posedge reset)
222	    begin
223	        if (reset)
224	            interrupt_req_prev <= '0;
225	        else
226	            interrupt_req_prev <= interrupt_req;
227	    end
228	
229	    assign interrupt_edge = interrupt_req & ~interrupt_req_prev;
230	
231	    genvar thread_idx;
232	    generate
233	        for (thread_idx = 0; thread_idx < `THREADS_PER_CORE; thread_idx++)
234	        begin : interrupt_gen
235	            logic[NUM_INTERRUPTS - 1:0] interrupt_ack;
236	            logic do_interrupt_ack;
237	
238	            assign do_interrupt_ack = dt_thread_idx == thread_idx
239	                && dd_creg_write_en
240	                && dd_creg_index == CR_INTERRUPT_ACK;
241	            assign interrupt_ack = {NUM_INTERRUPTS{do_interrupt_ack}}
242	                & dd_creg_write_val[NUM_INTERRUPTS - 1:0];
243	            assign cr_interrupt_en[thread_idx] = trap_state[thread_idx][0].flags.interrupt_en;
244	            assign cr_supervisor_en[thread_idx] = trap_state[thread_idx][0].flags.supervisor_en;
245	            assign cr_mmu_en[thread_idx] = trap_state[thread_idx][0].flags.mmu_en;
246	            assign cr_eret_subcycle[thread_idx] = trap_state[thread_idx][0].trap_subcycle;
247	            assign cr_eret_address[thread_idx] = trap_state[thread_idx][0].trap_pc;
248	
249	            // interrupt_edge_latched is set when a [positive] edge triggered
250	            // interrupt occurs.
251	            always_ff @(posedge clk, posedge reset)
252	            begin
253	                if (reset)
254	                    interrupt_edge_latched[thread_idx] <= '0;
255	                else
256	                begin
257	                    interrupt_edge_latched[thread_idx] <=
258	                        (interrupt_edge_latched[thread_idx] & ~interrupt_ack)
259	                        | interrupt_edge;
260	                end
261	            end
262	
263	            // If the trigger type is 1 (level triggered), interrupt pending is
264	            // determined by level. Otherwise check interrupt_latch, which stores
265	            // if an edge has been detected.
266	            assign interrupt_pending[thread_idx] = (int_trigger_type & interrupt_req)
267	                | (~int_trigger_type & interrupt_edge_latched[thread_idx]);
268	
269	            // Output to pipeline indicates if any interrupts are pending for each
270	            // thread.
271	            assign cr_interrupt_pending[thread_idx] = |(interrupt_pending[thread_idx]
272	                & interrupt_mask[thread_idx]);
273	        end
274	    endgenerate
275	
276	    always_ff @(posedge clk)
277	    begin
278	        //
279	        // Read logic
280	        //
281	        if (dd_creg_read_en)
282	        begin
283	            unique case (dd_creg_index)
284	                CR_FLAGS:             cr_creg_read_val <= scalar_t'(trap_state[dt_thread_idx][0].flags);
285	                CR_SAVED_FLAGS:       cr_creg_read_val <= scalar_t'(trap_state[dt_thread_idx][1].flags);
286	                CR_THREAD_ID:         cr_creg_read_val <= scalar_t'({CORE_ID, dt_thread_idx});
287	                CR_TRAP_PC:           cr_creg_read_val <= trap_state[dt_thread_idx][0].trap_pc;
288	                CR_TRAP_CAUSE:        cr_creg_read_val <= scalar_t'(trap_state[dt_thread_idx][0].trap_cause);
289	                CR_TRAP_HANDLER:      cr_creg_read_val <= cr_trap_handler;
290	                CR_TRAP_ADDRESS:      cr_creg_read_val <= trap_state[dt_thread_idx][0].trap_access_addr;
291	                CR_TLB_MISS_HANDLER:  cr_creg_read_val <= cr_tlb_miss_handler;
292	                CR_CYCLE_COUNT:       cr_creg_read_val <= cycle_count;
293	                CR_SCRATCHPAD0:       cr_creg_read_val <= trap_state[dt_thread_idx][0].scratchpad0;
294	                CR_SCRATCHPAD1:       cr_creg_read_val <= trap_state[dt_thread_idx][0].scratchpad1;
295	                CR_SUBCYCLE:          cr_creg_read_val <= scalar_t'(trap_state[dt_thread_idx][0].trap_subcycle);
296	                CR_CURRENT_ASID:      cr_creg_read_val <= scalar_t'(cr_current_asid[dt_thread_idx]);
297	                CR_PAGE_DIR:          cr_creg_read_val <= page_dir_base[dt_thread_idx];
298	                CR_INTERRUPT_PENDING: cr_creg_read_val <= scalar_t'(interrupt_pending[dt_thread_idx]
299	                                                          & interrupt_mask[dt_thread_idx]);
300	                CR_INTERRUPT_ENABLE:  cr_creg_read_val <= scalar_t'(interrupt_mask[dt_thread_idx]);
301	                CR_INTERRUPT_TRIGGER: cr_creg_read_val <= scalar_t'(int_trigger_type);
302	                CR_JTAG_DATA:         cr_creg_read_val <= jtag_data;
303	                CR_SYSCALL_INDEX:     cr_creg_read_val <= scalar_t'(trap_state[dt_thread_idx][0].syscall_index);
304	                CR_PERF_EVENT_COUNT0_L: cr_creg_read_val <= perf_event_count0[31:0];
305	                CR_PERF_EVENT_COUNT0_H: cr_creg_read_val <= perf_event_count0[63:32];
306	                CR_PERF_EVENT_COUNT1_L: cr_creg_read_val <= perf_event_count1[31:0];
307	                CR_PERF_EVENT_COUNT1_H: cr_creg_read_val <= perf_event_count1[63:32];
308	                default:              cr_creg_read_val <= 32'hffffffff;
309	            endcase
310	        end
311	    end
312	endmodule
313

